package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/** Multi-column GROUP BY must keep keys and common COUNT state in primitive dense tables. */
public class LmdbNativePrimitiveGroupingTest {

	private static final String EX = "http://example.com/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			for (int i = 0; i < 600; i++) {
				IRI subject = vf.createIRI(EX, "s" + i);
				IRI predicate = vf.createIRI(EX, "p" + (i % 3));
				IRI object = vf.createIRI(EX, "o" + (i % 5));
				connection.add(subject, predicate, object);
			}
		}
		resetCounters();
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void twoKeyPlainCountsUseParallelPrimitiveState() {
		Map<String, Long> counts = groupedCounts("COUNT(?s)");

		assertThat(counts).hasSize(15).allSatisfy((key, count) -> assertThat(count).isEqualTo(40L));
		assertThat(NativeGroupIteration.PRIMITIVE_COUNT_GROUP_ROWS.get()).isEqualTo(600L);
		assertThat(NativeGroupIteration.PRIMITIVE_TUPLE_GROUP_ROWS.get()).isZero();
		assertThat(PrimitiveTupleTable.INSERTIONS.get()).isEqualTo(15L);
	}

	@Test
	public void twoKeyDistinctCountsUsePrimitiveKeysWithGenericAggregateState() {
		Map<String, Long> counts = groupedCounts("COUNT(DISTINCT ?s)");

		assertThat(counts).hasSize(15).allSatisfy((key, count) -> assertThat(count).isEqualTo(40L));
		assertThat(NativeGroupIteration.PRIMITIVE_COUNT_GROUP_ROWS.get()).isZero();
		assertThat(NativeGroupIteration.PRIMITIVE_TUPLE_GROUP_ROWS.get()).isEqualTo(600L);
		assertThat(PrimitiveTupleTable.INSERTIONS.get()).isEqualTo(15L);
	}

	@Test
	public void singleKeyDistinctAggregationKeepsSpecializedMap() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			List<BindingSet> rows = QueryResults.asList(connection.prepareTupleQuery("""
					SELECT ?p (COUNT(?s) AS ?count) (COUNT(DISTINCT ?s) AS ?distinctCount)
					WHERE {
						{ ?s ?p ?o }
						UNION
						{ ?s ?p ?o }
					}
					GROUP BY ?p
					""").evaluate());

			assertThat(rows).hasSize(3).allSatisfy(row -> {
				assertThat(((Literal) row.getValue("count")).longValue()).isEqualTo(400L);
				assertThat(((Literal) row.getValue("distinctCount")).longValue()).isEqualTo(200L);
			});
		}

		assertThat(NativeGroupIteration.PRIMITIVE_COUNT_GROUP_ROWS.get()).isZero();
		assertThat(NativeGroupIteration.PRIMITIVE_TUPLE_GROUP_ROWS.get()).isZero();
		assertThat(PrimitiveTupleTable.PROBES.get()).isZero();
		assertThat(PrimitiveTupleTable.INSERTIONS.get()).isZero();
	}

	@Test
	public void orderedSinglePatternGroupingKeepsOnlyTheActiveAggregateState() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			List<BindingSet> rows = QueryResults.asList(connection.prepareTupleQuery(
					"SELECT ?p (COUNT(?s) AS ?c) WHERE { ?s ?p ?o } GROUP BY ?p").evaluate());
			assertThat(rows).hasSize(3)
					.allSatisfy(
							row -> assertThat(((Literal) row.getValue("c")).longValue()).isEqualTo(200L));
		}

		assertThat(NativeGroupIteration.ORDERED_GROUP_ROWS.get()).isEqualTo(600L);
		assertThat(NativeGroupIteration.ORDERED_GROUPS.get()).isEqualTo(3L);
		assertThat(NativeGroupIteration.PRIMITIVE_COUNT_GROUP_ROWS.get()).isZero();
	}

	private Map<String, Long> groupedCounts(String aggregate) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			List<BindingSet> rows = QueryResults.asList(connection.prepareTupleQuery(
					"SELECT ?p ?o (" + aggregate + " AS ?c) WHERE { ?s ?p ?o } GROUP BY ?p ?o").evaluate());
			Map<String, Long> counts = new HashMap<>();
			for (BindingSet row : rows) {
				counts.put(row.getValue("p").stringValue() + "|" + row.getValue("o").stringValue(),
						((Literal) row.getValue("c")).longValue());
			}
			return counts;
		}
	}

	private static void resetCounters() {
		NativeGroupIteration.PRIMITIVE_COUNT_GROUP_ROWS.set(0L);
		NativeGroupIteration.PRIMITIVE_TUPLE_GROUP_ROWS.set(0L);
		PrimitiveTupleTable.PROBES.set(0L);
		PrimitiveTupleTable.INSERTIONS.set(0L);
		NativeGroupIteration.ORDERED_GROUP_ROWS.set(0L);
		NativeGroupIteration.ORDERED_GROUPS.set(0L);
	}
}
